actions.script:
const DOMAIN = "${domain}";
const txt = (el) => el ? (el.textContent || "").trim() : null;

// Google Maps shows a "can't find <query>" banner when a search has no place.
// Detect it so we can return notfound immediately instead of waiting out the
// full panel timeout (the slow path for every domain with no listing).
function noResults() {
  const t = (document.body && document.body.innerText) || "";
  return /can't find|cannot find|couldn't find|no results found|did not match any|spelled correctly/i.test(t);
}

// Wait (bounded) for the single place panel to render, OR for a definitive
// no-results state. Maps loads the panel via XHR after the initial HTML, and a
// domain query usually auto-opens one place.
async function waitForPanel(timeoutMs) {
  const start = Date.now();
  let main = null;
  while (Date.now() - start < timeoutMs) {
    main = document.querySelector('div[role="main"][aria-label]');
    // Panel is ready once it has a name (aria-label) and an h1 title.
    if (main && main.getAttribute('aria-label') && document.querySelector('h1')) {
      return { state: 'found', main: main };
    }
    // Bail early on the no-results banner.
    if (noResults()) return { state: 'notfound', main: null };
    await new Promise((r) => setTimeout(r, 300));
  }
  return { state: 'timeout', main: document.querySelector('div[role="main"][aria-label]') };
}

const panel = await waitForPanel(12000);

// Fast path: Google explicitly couldn't find the domain.
if (panel.state === 'notfound') {
  return JSON.stringify({
    results: [{
      domain_name: DOMAIN, status: "notfound",
      name: null, address: null, website: null, rating: null, review_count: null
    }]
  });
}

const main = panel.main;
const root = main || document;

let name = null, address = null, website = null, rating = null, review_count = null;

// name: the place panel's aria-label, else the first h1.
if (main && main.getAttribute('aria-label')) name = main.getAttribute('aria-label').trim();
if (!name) name = txt(document.querySelector('h1'));

// rating + review count.
try {
  const block = root.querySelector('div.F7nice');
  if (block) {
    const rt = block.querySelector('span[aria-hidden="true"]');
    if (rt) { const v = parseFloat((txt(rt) || "").replace(',', '.')); if (!isNaN(v)) rating = v; }
    const rv = block.querySelector('span[aria-label]');
    if (rv) { const m = (rv.getAttribute('aria-label') || "").replace(/[^0-9]/g, ''); if (m) review_count = parseInt(m, 10); }
  }
  if (rating === null || review_count === null) {
    const cand = Array.from(root.querySelectorAll('[aria-label]'))
      .map((e) => e.getAttribute('aria-label') || "")
      .find((a) => /stars?/i.test(a) && /review|rating/i.test(a));
    if (cand) {
      const rm = cand.match(/([0-9]+(?:[.,][0-9]+)?)\s*stars?/i);
      if (rm && rating === null) rating = parseFloat(rm[1].replace(',', '.'));
      const cm = cand.match(/([0-9][0-9,\.]*)\s*reviews?/i);
      if (cm && review_count === null) review_count = parseInt(cm[1].replace(/[^0-9]/g, ''), 10);
    }
  }
} catch (e) {}

// address.
try {
  const a = root.querySelector('button[data-item-id="address"]') ||
            root.querySelector('[data-tooltip="Copy address"]');
  if (a) {
    const al = a.getAttribute('aria-label');
    address = al ? al.replace(/^Address:\s*/i, '').trim() : txt(a);
  }
} catch (e) {}

// website.
try {
  const w = root.querySelector('a[data-item-id="authority"]') ||
            root.querySelector('a[aria-label^="Website"]') ||
            root.querySelector('[data-tooltip="Open website"]');
  if (w) {
    website = w.getAttribute('href') ||
              (w.getAttribute('aria-label') || "").replace(/^Website:\s*/i, '').trim();
  }
} catch (e) {}

const found = !!(name || website || address);
return JSON.stringify({
  results: [{
    domain_name: DOMAIN,
    status: found ? "completed" : "notfound",
    name: name,
    address: address,
    website: website,
    rating: rating,
    review_count: review_count
  }]
});
